service-task-definition.script:
const main = () => {
    ////// == 工程コンフィグ・ワークフローデータの参照 / Config & Data Retrieving ==
    const channelName = retrieveChannelName();
    const messageId = retrieveMessageId();
    const markdown = configs.get('conf_Markdown') ?? '';
    const files = retrieveFiles();

    if (markdown === '' && files.length === 0) {
        throw new Error('Post content and attached files are both empty.');
    }

    ////// == 演算 / Calculating ==
    const postId = post(channelName, messageId, markdown, files);

    ////// == ワークフローデータへの代入 / Data Updating ==
    saveData('conf_PostId', new java.math.BigDecimal(postId));
};

/**
 * config から投稿先チャンネル名を読み出す
 * 空の場合、この工程を処理しているケースのチャンネル名を返す
 * @returns {String}
 */
const retrieveChannelName = () => {
    const channelName = configs.get('conf_ChannelName') ?? '';
    if (channelName !== '') {
        return channelName;
    }
    return `p${processInstance.getProcessInstanceId()}`;
};

/**
 * config から投稿先メッセージ ID を読み出す
 * 未設定の場合、null を返す
 * @returns {Number|null}
 */
const retrieveMessageId = () => {
    const def = configs.getObject('conf_MessageId');
    if (def === null) {
        return null;
    }
    const messageId = engine.findData(def);
    if (messageId === null) {
        return null;
    }
    return messageId.longValue();
};

/**
 * config から添付ファイルを読み出す
 * 未設定の場合、空配列を返す
 * @returns {Array<QfileView>}
 */
const retrieveFiles = () => {
    const def = configs.getObject('conf_Files');
    if (def === null) {
        return [];
    }
    return engine.findData(def) ?? [];
};

/**
 * コラボチャットに投稿する
 * @param {String} channelName
 * @param {Number|null} messageId
 * @param {String} markdown
 * @param {Array} files
 * @returns {Number} 投稿したメッセージ／コメントの ID
 */
const post = (channelName, messageId, markdown, files) => {
    let feedWrapper = feedService.begin()
        .setChannel(channelName);
    if (messageId !== null) {
        feedWrapper = feedWrapper.setMessageId(messageId);
    }
    if (markdown !== '') {
        feedWrapper = feedWrapper.setMarkdown(markdown);
    }
    files.forEach(file => feedWrapper.attachFile(file));
    return feedWrapper.post();
};

/**
 * データ項目への保存
 * @param {String} configName
 * @param {*} data
 */
const saveData = (configName, data) => {
    const def = configs.getObject(configName);
    if (def === null) {
        return;
    }
    engine.setData(def, data);
};

service-task-definition.test:
/**
 * 設定の準備
 * @param {String} channelName C1（空文字で未設定扱い）
 * @param {Number|null} messageId C2（null で未設定）
 * @param {String} markdown C3
 * @param {Array|null} files C4（null で未設定）
 * @param {Boolean} savePostId C5 を設定するか
 */
const prepareConfigs = (channelName, messageId, markdown, files, savePostId) => {
    configs.put('conf_ChannelName', channelName);

    if (messageId !== null) {
        const messageIdDef = engine.createDataDefinition('投稿先メッセージ ID', 1, 'q_messageId', 'DECIMAL');
        engine.setData(messageIdDef, new java.math.BigDecimal(messageId));
        configs.putObject('conf_MessageId', messageIdDef);
    }

    configs.put('conf_Markdown', markdown);

    if (files !== null) {
        const filesDef = engine.createDataDefinition('添付ファイル', 2, 'q_files', 'FILE');
        engine.setData(filesDef, files);
        configs.putObject('conf_Files', filesDef);
    }

    if (savePostId) {
        const postIdDef = engine.createDataDefinition('投稿 ID', 3, 'q_postId', 'DECIMAL');
        configs.putObject('conf_PostId', postIdDef);
    }
};

/**
 * 異常系のテスト
 * @param {String} errorMsg
 */
const assertError = (errorMsg) => {
    let failed = false;
    try {
        main();
    } catch (e) {
        failed = true;
        expect(e.message).toEqual(errorMsg);
    }
    if (!failed) {
        fail('No error was thrown.');
    }
};

/**
 * 投稿文も添付ファイルもない場合、エラー
 */
test('Error - markdown and files are both empty', () => {
    prepareConfigs('my-channel', null, '', null, false);
    assertError('Post content and attached files are both empty.');
});

/**
 * 投稿成功
 * - チャンネル名指定あり
 * - メッセージ ID なし（新規メッセージ）
 * - 投稿文あり・添付ファイルなし・投稿 ID 保存なし
 */
test('Success - markdown only, new message, postId not saved', () => {
    prepareConfigs('my-channel', null, '**Hello**', null, false);
    main();
});

/**
 * 投稿成功
 * - チャンネル名空 → ケースのチャンネルを使用
 */
test('Success - channel name blank (uses case channel)', () => {
    prepareConfigs('', null, 'Hello', null, false);
    main();
});

/**
 * 投稿成功
 * - メッセージ ID あり（コメント投稿）
 * - 投稿 ID 保存あり
 */
test('Success - with messageId (comment), postId saved', () => {
    prepareConfigs('my-channel', 9999, 'Comment', null, true);
    main();

    const postIdDef = configs.getObject('conf_PostId');
    expect(engine.findData(postIdDef) !== null).toEqual(true);
});

/**
 * 投稿成功
 * - 添付ファイルあり・投稿文なし
 */
test('Success - files only, no markdown', () => {
    const file = engine.createQfile('test.txt', 'text/plain', 'test');
    prepareConfigs('my-channel', null, '', [file], false);
    main();
});

/**
 * 投稿成功
 * - 全項目設定（投稿文・添付ファイル・メッセージ ID・投稿 ID 保存）
 */
test('Success - all configs', () => {
    const file = engine.createQfile('test.txt', 'text/plain', 'test');
    prepareConfigs('my-channel', 9999, '**Hello**', [file], true);
    main();

    const postIdDef = configs.getObject('conf_PostId');
    expect(engine.findData(postIdDef) !== null).toEqual(true);
});
